const firstInsuranceSurcharge = (amount: number): number =>
  amount * FIRST_INSURANCE_SURCHARGE_RATE;

const loyaltyDiscount = (basePremium: number, yearsWithMHPCO: number): number =>
  yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
    ? basePremium * LOYALTY_DISCOUNT_RATE
    : 0;

const quotePremiumFor = (items: Item[], yearsWithMHPCO: number): number => {
  const policyBase = itemsBasePremium(items);
  return Math.ceil(
    policyBase +
      itemSurchargesTotal(items) +
      firstInsuranceSurcharge(policyBase) -
      loyaltyDiscount(policyBase, yearsWithMHPCO) +
      PROCESSING_FEE,
  );
};

export const runScenario = (input: Scenario): unknown =>
  quoteResult(quotePremiumFor(input.steps[0].items, input.customer.yearsWithMHPCO));
